// Mode: Run Once for Each Item
const e = $input.item.json;
const reviews = Array.isArray(e.reviews) ? e.reviews : [];

const validos = reviews.filter(
  r => r && r.review_text && r.review_text.trim().length > 0
);

const comentarios_formatados = validos
  .sort((a, b) => (b.iso_date_timestamp || 0) - (a.iso_date_timestamp || 0))
  .map((r, i) => `Comentário ${i + 1}: ${r.review_text.trim()}`)
  .join("\n\n");

return {
  json: {
    ...e,                                    // preserva id, nome, reviews, tudo
    comentarios_formatados: comentarios_formatados || "",
    qtd_comentarios_reais: validos.length
  }
};

// =============================================================================
// n8n Code Node — Análise estatística + Avaliação por categoria
// Modo: Run Once for All Items
// Input:  $input.all() (estabelecimentos crus do scraping)
// Output: return [{ json: {...} }]
//
// Mínimo de avaliações (minimum_reviews) lido do próprio estabelecimento,
// com fallback para 10 quando o campo não vem.
// =============================================================================

// ===== HELPERS =====
const round = (x, d = 4) => {
  if (x === null || x === undefined || Number.isNaN(x) || !Number.isFinite(x)) return null;
  const f = Math.pow(10, d);
  return Math.round(x * f) / f;
};
const clamp = (x, lo, hi) => Math.min(Math.max(x, lo), hi);

const cumulative = (dist) => {
  const c = [0];
  for (let i = 0; i < dist.length; i++) c.push(c[i] + dist[i]);
  return c;
};

const quantilDiscreto = (dist, n, p) => {
  const alvo = p * n;
  let acc = 0;
  for (let i = 0; i < dist.length; i++) {
    acc += dist[i];
    if (acc >= alvo) return i + 1;
  }
  return dist.length;
};

const mean = (arr) => (arr.length ? arr.reduce((a, b) => a + b, 0) / arr.length : null);

// === BLOCO 1 — Tendência central ===
function tendenciaCentral(dist, n) {
  if (n === 0) return null;
  let soma = 0;
  for (let i = 0; i < 5; i++) soma += (i + 1) * dist[i];
  const media = soma / n;

  const corteInf = 0.10 * n;
  const corteSup = 0.90 * n;
  const cum = cumulative(dist);
  let pesoTotal = 0, somaTrunc = 0;
  for (let i = 0; i < 5; i++) {
    const inicio = cum[i], fim = cum[i + 1];
    const peso = Math.max(0, Math.min(fim, corteSup) - Math.max(inicio, corteInf));
    pesoTotal += peso;
    somaTrunc += (i + 1) * peso;
  }
  const mediaTrunc = pesoTotal > 0 ? somaTrunc / pesoTotal : media;

  const k = 2;
  const nLap = n + 5 * k;
  let somaLap = 0;
  for (let i = 0; i < 5; i++) somaLap += (i + 1) * (dist[i] + k);
  const mediaLaplace = somaLap / nLap;

  const mediana = quantilDiscreto(dist, n, 0.5);
  let moda = 1, maxF = -1;
  for (let i = 0; i < 5; i++) if (dist[i] > maxF) { maxF = dist[i]; moda = i + 1; }
  const q1 = quantilDiscreto(dist, n, 0.25);
  const q3 = quantilDiscreto(dist, n, 0.75);

  return {
    media: round(media, 4),
    media_truncada_10: round(mediaTrunc, 4),
    media_laplace: round(mediaLaplace, 4),
    mediana, moda, q1, q3, iqr: q3 - q1,
  };
}

// === BLOCO 2 — Dispersão e forma ===
function dispersaoForma(dist, n, media) {
  if (n === 0 || media === null) return null;
  let m2 = 0, m3 = 0, m4 = 0;
  for (let i = 0; i < 5; i++) {
    const d = (i + 1) - media;
    const d2 = d * d;
    m2 += d2 * dist[i];
    m3 += d2 * d * dist[i];
    m4 += d2 * d2 * dist[i];
  }
  m2 /= n; m3 /= n; m4 /= n;

  const variancia = m2;
  const desvio = Math.sqrt(variancia);
  const cv = media !== 0 ? desvio / media : null;
  const assimetria = m2 > 0 ? m3 / Math.pow(m2, 1.5) : 0;
  const curtose = m2 > 0 ? (m4 / (m2 * m2)) - 3 : 0;

  let H = 0;
  for (let i = 0; i < 5; i++) {
    const p = dist[i] / n;
    if (p > 0) H -= p * Math.log2(p);
  }
  const Hmax = Math.log2(5);

  return {
    variancia: round(variancia, 4),
    desvio_padrao: round(desvio, 4),
    coef_variacao: round(cv, 4),
    assimetria: round(assimetria, 4),
    curtose_excesso: round(curtose, 4),
    entropia_shannon: round(H, 4),
    entropia_normalizada: round(H / Hmax, 4),
  };
}

// === BLOCO 3 — Inferência ===
function inferencia(media, variancia, n) {
  if (n === 0) return null;
  const desvio = Math.sqrt(variancia);
  const erroPadrao = desvio / Math.sqrt(n);
  const z95 = 1.96, z99 = 2.576;

  const icNormal = (z) => {
    const inf = clamp(media - z * erroPadrao, 1, 5);
    const sup = clamp(media + z * erroPadrao, 1, 5);
    return { inferior: round(inf, 4), superior: round(sup, 4), amplitude: round(sup - inf, 4) };
  };

  const pHat = clamp((media - 1) / 4, 0, 1);
  const wilson = (z) => {
    const z2 = z * z;
    const denom = 1 + z2 / n;
    const centro = (pHat + z2 / (2 * n)) / denom;
    const margem = z * Math.sqrt((pHat * (1 - pHat) + z2 / (4 * n)) / n) / denom;
    const inf = clamp(1 + 4 * Math.max(0, centro - margem), 1, 5);
    const sup = clamp(1 + 4 * Math.min(1, centro + margem), 1, 5);
    return { inferior: round(inf, 4), superior: round(sup, 4), amplitude: round(sup - inf, 4) };
  };

  const a = 2 + n * pHat;
  const b = 2 + n * (1 - pHat);
  const meanPost = a / (a + b);
  const sdPost = Math.sqrt((a * b) / ((a + b) * (a + b) * (a + b + 1)));
  const bayes = (z) => {
    const inf = clamp(1 + 4 * Math.max(0, meanPost - z * sdPost), 1, 5);
    const sup = clamp(1 + 4 * Math.min(1, meanPost + z * sdPost), 1, 5);
    return { inferior: round(inf, 4), superior: round(sup, 4), amplitude: round(sup - inf, 4) };
  };

  return {
    normal_95: icNormal(z95), normal_99: icNormal(z99),
    wilson_95: wilson(z95),   wilson_99: wilson(z99),
    bayes_95: bayes(z95),     bayes_99: bayes(z99),
    posterior_beta: {
      alpha: round(a, 4), beta: round(b, 4),
      media_posterior_rescalada: round(1 + 4 * meanPost, 4),
    },
  };
}

// === BLOCO 4 — Sentimento ===
function sentimento(dist, n) {
  if (n === 0) return null;
  const p = dist.map(x => x / n);
  const pctNeg = (p[0] + p[1]) * 100;
  const pctNeu = p[2] * 100;
  const pctPos = (p[3] + p[4]) * 100;
  const razao = (p[0] + p[1]) > 0 ? (p[3] + p[4]) / (p[0] + p[1]) : null;
  const nps = (p[4] - (p[0] + p[1])) * 100;
  return {
    pct_negativas: round(pctNeg, 2),
    pct_neutras: round(pctNeu, 2),
    pct_positivas: round(pctPos, 2),
    razao_pos_neg: round(razao, 3),
    nps_adaptado: round(nps, 2),
    top_box: round(p[4] * 100, 2),
    top_2_box: round((p[3] + p[4]) * 100, 2),
    bottom_box: round(p[0] * 100, 2),
    bottom_2_box: round((p[0] + p[1]) * 100, 2),
    proporcoes: p.map(x => round(x, 4)),
  };
}

// === BLOCO 5 — Diagnóstico de forma ===
function diagnosticoForma(dist, n, variancia) {
  if (n === 0) return null;
  const p = dist.map(x => x / n);
  const distUniforme = p.reduce((s, x) => s + Math.abs(x - 0.2), 0) / 2;
  const indicePol = variancia / 4;
  const maxP = Math.max(...p);
  const idxMax = p.indexOf(maxP);

  let formato;
  if (maxP > 0.7) formato = `concentrado em ${idxMax + 1}★`;
  else if (p.every(x => x >= 0.15 && x <= 0.25)) formato = "uniforme";
  else if (p[4] > p[3] && p[3] > p[2] && p[2] > p[1] && p[1] > p[0] && p[4] > 0.4)
    formato = "decrescente típico (J invertido, positivo saudável)";
  else if ((p[0] + p[4]) > 0.5 && (p[2] + p[3]) < 0.3) formato = "polarizado / bimodal";
  else if ((p[0] + p[4]) > 0.5 && p[2] < p[0] && p[2] < p[4]) formato = "J shape (bias de seleção, vale no meio)";
  else if (idxMax === 2) formato = "centrado em 3★ (mediano)";
  else if (p[4] >= p[3] && p[3] >= p[2]) formato = "predominantemente positivo";
  else if (p[0] >= p[1] && p[1] >= p[2]) formato = "predominantemente negativo";
  else formato = "misto / sem padrão claro";

  return {
    formato,
    distancia_uniforme: round(distUniforme, 4),
    indice_polarizacao: round(indicePol, 4),
  };
}

// === BLOCO 6 — Temporal ===
function temporal(reviews) {
  if (!Array.isArray(reviews) || reviews.length === 0)
    return { _aviso: "Sem reviews amostradas — análise temporal indisponível", amostra_size: 0 };

  const items = reviews
    .map(r => {
      const tsRaw = r?.iso_date_timestamp;
      const ts = (typeof tsRaw === "number" && tsRaw > 0) ? tsRaw / 1000 : null;
      const rate = typeof r?.review_rate === "number" ? r.review_rate : null;
      return (ts !== null && rate !== null) ? { ts, rate, date: new Date(ts) } : null;
    })
    .filter(Boolean)
    .sort((a, b) => a.ts - b.ts);

  if (items.length === 0) return { _aviso: "Sem timestamps válidos na amostra", amostra_size: 0 };

  const agora = Date.now();
  const DIA = 86400 * 1000;
  const mediaJanela = (dias) => {
    const limite = agora - dias * DIA;
    const sub = items.filter(x => x.ts >= limite);
    if (sub.length === 0) return null;
    return { media: round(mean(sub.map(x => x.rate)), 3), n: sub.length };
  };

  let comparacaoMetades = null;
  if (items.length >= 4) {
    const mid = Math.floor(items.length / 2);
    const antiga = items.slice(0, mid);
    const recente = items.slice(items.length - mid);
    const mAnt = mean(antiga.map(x => x.rate));
    const mRec = mean(recente.map(x => x.rate));
    const delta = mRec - mAnt;
    let direcao = "estável";
    if (delta > 0.5) direcao = "melhorando";
    else if (delta < -0.5) direcao = "piorando";
    comparacaoMetades = {
      media_metade_antiga: round(mAnt, 3),
      media_metade_recente: round(mRec, 3),
      delta: round(delta, 3),
      direcao,
    };
  }

  let regressao = null;
  if (items.length >= 3) {
    const t0 = items[0].ts;
    const xs = items.map(x => (x.ts - t0) / DIA);
    const ys = items.map(x => x.rate);
    const nL = xs.length;
    const sx = xs.reduce((a, b) => a + b, 0);
    const sy = ys.reduce((a, b) => a + b, 0);
    const sxx = xs.reduce((a, b) => a + b * b, 0);
    const sxy = xs.reduce((a, b, i) => a + b * ys[i], 0);
    const denom = nL * sxx - sx * sx;
    const slope = denom !== 0 ? (nL * sxy - sx * sy) / denom : 0;
    const slopeAno = slope * 365.25;
    let interp = "estável";
    if (slopeAno > 0.3) interp = "melhora clara";
    else if (slopeAno < -0.3) interp = "queda clara";
    else if (slopeAno > 0.1) interp = "leve melhora";
    else if (slopeAno < -0.1) interp = "leve queda";
    regressao = { slope_por_dia: round(slope, 6), slope_estrelas_por_ano: round(slopeAno, 4), interpretacao: interp };
  }

  const periodoDias = (items[items.length - 1].ts - items[0].ts) / DIA;
  const reviewsPorMes = periodoDias > 0 ? (items.length / periodoDias) * 30 : null;
  const fimSemana = [], diasUteis = [];
  for (const it of items) {
    const dow = it.date.getUTCDay();
    (dow === 0 || dow === 6 ? fimSemana : diasUteis).push(it.rate);
  }
  const diasDesdeUltima = (agora - items[items.length - 1].ts) / DIA;

  return {
    _aviso: "Métricas baseadas APENAS na amostra de reviews — não na população completa",
    amostra_size: items.length,
    ultimos_30_dias: mediaJanela(30),
    ultimos_90_dias: mediaJanela(90),
    ultimos_180_dias: mediaJanela(180),
    ultimos_365_dias: mediaJanela(365),
    comparacao_metades: comparacaoMetades,
    regressao_linear: regressao,
    reviews_por_mes_amostra: round(reviewsPorMes, 3),
    periodo_coberto_dias: round(periodoDias, 1),
    media_fim_de_semana: round(mean(fimSemana), 3),
    media_dias_uteis: round(mean(diasUteis), 3),
    dias_desde_ultima_review: round(diasDesdeUltima, 1),
  };
}

// === BLOCO 7 — Credibilidade ===
function credibilidade(reviews) {
  if (!Array.isArray(reviews) || reviews.length === 0)
    return { _aviso: "Sem reviews amostradas", amostra_size: 0 };
  const valid = reviews.filter(r => r);
  if (valid.length === 0) return { _aviso: "Sem reviews válidas", amostra_size: 0 };

  const totRevs = valid.map(r => r?.user_total_reviews ?? 0);
  const sorted = [...totRevs].sort((a, b) => a - b);
  const medianaTot = sorted.length % 2 === 1
    ? sorted[Math.floor(sorted.length / 2)]
    : (sorted[sorted.length / 2 - 1] + sorted[sorted.length / 2]) / 2;

  const novatos = [], intermediarios = [], experientes = [];
  for (const r of valid) {
    const t = r?.user_total_reviews ?? 0;
    const rate = typeof r?.review_rate === "number" ? r.review_rate : null;
    if (rate === null) continue;
    if (t <= 2) novatos.push(rate);
    else if (t <= 10) intermediarios.push(rate);
    else experientes.push(rate);
  }
  const mediaNov = mean(novatos);
  const mediaExp = mean(experientes);
  const diffExpNov = (mediaExp !== null && mediaNov !== null) ? mediaExp - mediaNov : null;
  const total = valid.length;
  const comFoto = valid.filter(r => Array.isArray(r?.review_photos) && r.review_photos.length > 0).length;
  const comTexto = valid.filter(r => r?.review_text && String(r.review_text).trim().length > 0).length;
  const compTexto = valid.filter(r => r?.review_text).map(r => String(r.review_text).length);

  return {
    amostra_size: total,
    media_user_total_reviews: round(mean(totRevs), 2),
    mediana_user_total_reviews: round(medianaTot, 1),
    pct_novatos: round((novatos.length / total) * 100, 2),
    pct_intermediarios: round((intermediarios.length / total) * 100, 2),
    pct_experientes: round((experientes.length / total) * 100, 2),
    media_nota_novatos: round(mediaNov, 3),
    media_nota_intermediarios: round(mean(intermediarios), 3),
    media_nota_experientes: round(mediaExp, 3),
    diff_experientes_vs_novatos: round(diffExpNov, 3),
    pct_com_foto: round((comFoto / total) * 100, 2),
    pct_com_texto: round((comTexto / total) * 100, 2),
    comprimento_medio_texto: round(mean(compTexto) ?? 0, 1),
  };
}

// === BLOCO 8 — Textual ===
const STOPWORDS_PT = new Set([
  "a","o","e","de","da","do","das","dos","para","com","que","em","no","na","nos","nas",
  "um","uma","uns","umas","os","as","se","por","ao","aos","mas","como","muito","mais",
  "foi","ser","esta","estao","tambem","so","ja","sem","ou","isso","esse","essa","este",
  "ele","ela","eles","elas","eu","voce","voces","minha","meu","seu","sua","nao",
  "sim","sao","tem","ter","fui","vai","vou","todos","todas","todo","toda","pelo",
  "pela","pelos","pelas","quando","onde","aqui","ali","la","entao","porque","pois",
  "the","and","for","with","this","that","you","are","was","were",
]);
function tokenizar(texto) {
  if (!texto) return [];
  return String(texto).toLowerCase()
    .normalize("NFD").replace(/[\u0300-\u036f]/g, "")
    .replace(/[^a-z0-9\s]/g, " ")
    .split(/\s+/)
    .filter(w => w.length >= 4 && !STOPWORDS_PT.has(w));
}
function topPalavras(textos, top = 10) {
  const freq = {};
  for (const t of textos) for (const w of tokenizar(t)) freq[w] = (freq[w] || 0) + 1;
  return Object.entries(freq).sort((a, b) => b[1] - a[1]).slice(0, top).map(([w, c]) => ({ palavra: w, freq: c }));
}
function analiseTextual(reviews) {
  if (!Array.isArray(reviews) || reviews.length === 0)
    return { _aviso: "Sem reviews amostradas", amostra_size: 0 };
  const valid = reviews.filter(r => r);
  const positivas = valid.filter(r => (r?.review_rate ?? 0) >= 4);
  const negativas = valid.filter(r => (r?.review_rate ?? 0) <= 2 && (r?.review_rate ?? 0) > 0);

  const compMedio = (arr) => {
    const c = arr.map(r => r?.review_text ? String(r.review_text).length : 0).filter(x => x > 0);
    return c.length > 0 ? mean(c) : 0;
  };
  const hasResp = (r) => Boolean(r?.business_response_text || r?.owner_answer);
  const respGeral = valid.length > 0 ? valid.filter(hasResp).length / valid.length : 0;
  const respNeg = negativas.length > 0 ? negativas.filter(hasResp).length / negativas.length : null;
  const respPos = positivas.length > 0 ? positivas.filter(hasResp).length / positivas.length : null;

  return {
    amostra_size: valid.length,
    comprimento_medio_positivas: round(compMedio(positivas), 1),
    comprimento_medio_negativas: round(compMedio(negativas), 1),
    top_palavras_positivas: topPalavras(positivas.map(r => r?.review_text), 10),
    top_palavras_negativas: topPalavras(negativas.map(r => r?.review_text), 10),
    taxa_resposta_geral: round(respGeral * 100, 2),
    taxa_resposta_negativas: respNeg !== null ? round(respNeg * 100, 2) : null,
    taxa_resposta_positivas: respPos !== null ? round(respPos * 100, 2) : null,
    proprietario_engajado: respGeral >= 0.3,
  };
}

// === BLOCO 9 — Red flags ===
function redFlags(ctx) {
  const flags = [];
  const add = (severidade, flag, detalhe) => flags.push({ severidade, flag, detalhe });
  const { divergencia, notaGoogle, mediaCalc, temporalData, n, minReviews, wilson95, credData, diagData, textualData } = ctx;

  if (notaGoogle !== null && Math.abs(divergencia) > 0.15)
    add("média", "Divergência entre nota do Google e média calculada",
      `Google=${notaGoogle}, calculada=${round(mediaCalc, 3)} (Δ=${round(divergencia, 3)})`);

  const delta = temporalData?.comparacao_metades?.delta;
  if (typeof delta === "number" && delta < -0.7)
    add("alta", "Queda forte na qualidade ao longo do tempo", `Delta entre metades: ${delta}`);

  const d = temporalData?.dias_desde_ultima_review;
  if (typeof d === "number") {
    if (d > 365) add("alta", "Sem reviews há mais de 1 ano (na amostra)", `${d} dias`);
    else if (d > 180) add("média", "Sem reviews há mais de 6 meses (na amostra)", `${d} dias`);
  }
  if (diagData?.formato?.includes("polarizado"))
    add("média", "Distribuição polarizada", "Muitas notas extremas (1★ e 5★), pouco meio — opiniões divididas");
  if (diagData?.formato?.includes("J shape"))
    add("baixa", "Possível viés de seleção", "J shape — clientes engajados só nos extremos da experiência");
  if (n < minReviews)
    add("alta", "Amostra abaixo do mínimo",
      `Apenas ${n} de ${minReviews} avaliações mínimas — estatísticas pouco confiáveis`);
  if (wilson95 && wilson95.amplitude > 1.5)
    add("média", "IC 95% (Wilson) muito amplo", `Amplitude de ${wilson95.amplitude} estrelas — alta incerteza sobre a média verdadeira`);
  if (credData?.pct_novatos !== undefined && credData.pct_novatos > 60)
    add("baixa", "Muitos avaliadores novatos", `${credData.pct_novatos}% têm ≤2 reviews`);
  const diff = credData?.diff_experientes_vs_novatos;
  if (typeof diff === "number" && Math.abs(diff) > 1.5)
    add("média", "Discrepância forte entre experientes e novatos", `Diferença de ${diff} estrelas — possível astroturfing`);
  const trn = textualData?.taxa_resposta_negativas;
  if (typeof trn === "number" && trn < 20 && (textualData?.amostra_size ?? 0) > 3)
    add("baixa", "Baixa taxa de resposta às reviews negativas", `Apenas ${trn}% das negativas receberam resposta`);

  return flags;
}

// === BLOCO 10 — Score composto e confiança ===
function classificarConfianca(n) {
  if (n < 5)   return { nivel: "insuficiente",  peso: 0.0 };
  if (n < 15)  return { nivel: "muito baixa",   peso: 0.2 };
  if (n < 30)  return { nivel: "baixa",         peso: 0.4 };
  if (n < 100) return { nivel: "média",         peso: 0.6 };
  if (n < 500) return { nivel: "alta",          peso: 0.8 };
  return         { nivel: "muito alta",         peso: 1.0 };
}
function scoreComposto({ wilson95, n, slopeAno, pctExperientes, indicePol }) {
  const notaBase    = clamp((wilson95.inferior - 1) / 4, 0, 1);
  const confAmostra = Math.min(1, Math.log10(n + 1) / Math.log10(501));
  const slope       = slopeAno ?? 0;
  const bonusTend   = clamp(0.5 + slope / 2, 0, 1);
  const bonusCred   = Math.min(1, (pctExperientes ?? 0) / 100 + 0.3);
  const penalPol    = indicePol ?? 0;
  let score = 0.50 * notaBase + 0.20 * confAmostra + 0.15 * bonusTend + 0.10 * bonusCred - 0.15 * penalPol;
  return round(clamp(score, 0, 1) * 10, 2);
}

// === BLOCO 11 — Veredicto ===
function classificarFaixa(score) {
  if (score >= 8.5) return "✅ Excelente";
  if (score >= 7.0) return "🟢 Muito bom";
  if (score >= 5.5) return "🟡 Bom";
  if (score >= 4.0) return "🟠 Regular";
  if (score >= 2.5) return "🔴 Ruim";
  return "⛔ Péssimo";
}
function recomendacaoFromFlags(flags) {
  const altas = flags.filter(f => f.severidade === "alta").length;
  const medias = flags.filter(f => f.severidade === "média").length;
  if (altas >= 2) return "Evitar — múltiplos sinais de alerta sérios";
  if (altas === 1) return "Verificar contexto antes de visitar — há um alerta importante";
  if (medias >= 3) return "Cautela — vários sinais de inconsistência";
  if (medias >= 1) return "Aceitável com ressalvas";
  return "Sem alertas relevantes — pode visitar com confiança";
}
function veredicto({ confianca, score, mediaCalc, n, wilson95, diagData, temporalData, flags }) {
  if (confianca.nivel === "insuficiente") {
    return {
      classificacao: "❌ Indeterminado", score_final: null,
      texto: `Apenas ${n} avaliação(ões) — dados insuficientes para um veredicto estatístico confiável.`,
      recomendacao: "Buscar outras fontes de informação ou aguardar mais avaliações.",
    };
  }
  const tendencia = temporalData?.regressao_linear?.interpretacao ?? "sem dados temporais suficientes";
  return {
    classificacao: classificarFaixa(score),
    score_final: score,
    texto: `Nota média de ${round(mediaCalc, 2)} estrelas, baseada em ${n} avaliações (confiança ${confianca.nivel}). IC 95% Wilson: [${wilson95.inferior}, ${wilson95.superior}]. Distribuição: ${diagData.formato}. Tendência temporal: ${tendencia}.`,
    recomendacao: recomendacaoFromFlags(flags),
  };
}

// =============================================================================
//   AVALIAÇÃO POR CATEGORIA
// =============================================================================

function confPopulacao(n) {
  if (n < 5)   return 10;
  if (n < 15)  return 35;
  if (n < 30)  return 55;
  if (n < 100) return 75;
  if (n < 500) return 90;
  return 97;
}
function confAmostra(k) {
  if (k < 3)  return 15;
  if (k < 5)  return 30;
  if (k < 10) return 50;
  if (k < 20) return 70;
  return 85;
}
function ajustarFronteira(base, valor, limiar, range = 0.5) {
  const dist = Math.abs(valor - limiar);
  if (dist >= range) return base;
  return base * (0.6 + 0.4 * (dist / range));
}
function montarCategoria({ nome, criterio, valor_observado, score, status, confiabilidade_pct, observacao }) {
  return {
    nome, status,
    score: round(score, 2),
    confiabilidade_pct: round(clamp(confiabilidade_pct, 0, 100), 1),
    criterio, valor_observado, observacao,
  };
}

function avaliarCategorias(analise, n) {
  const reviewsN = analise?.temporal?.amostra_size ?? 0;
  const cats = {};

  (() => {
    const m = analise.tendencia_central.media;
    const trunc = analise.tendencia_central.media_truncada_10;
    const consistencia = Math.abs(m - trunc);
    let status = "neutro";
    if (m >= 3.5) status = "aprovado";
    else if (m < 3.0) status = "reprovado";
    const score = clamp(((m - 1) / 4) * 10, 0, 10);
    let conf = confPopulacao(n);
    if (consistencia > 0.3) conf *= 0.85;
    const limiar = status === "aprovado" ? 3.5 : (status === "reprovado" ? 3.0 : 3.25);
    conf = ajustarFronteira(conf, m, limiar, 0.4);
    cats.tendencia = montarCategoria({
      nome: "Tendência Central",
      criterio: "Aprovado: média ≥ 3.5★. Reprovado: < 3.0★.",
      valor_observado: `média=${round(m, 2)}, truncada=${round(trunc, 2)}`,
      score, status, confiabilidade_pct: conf,
      observacao: `Média de ${round(m, 2)}★ com consistência ${consistencia < 0.3 ? "boa" : "fraca"} (|Δ truncada|=${round(consistencia, 2)})`,
    });
  })();

  (() => {
    const dp = analise.dispersao_forma.desvio_padrao;
    const cv = analise.dispersao_forma.coef_variacao;
    const ent = analise.dispersao_forma.entropia_normalizada;
    let status = "neutro";
    if (dp < 1.2) status = "aprovado";
    else if (dp >= 1.7) status = "reprovado";
    const score = clamp(10 - dp * 5, 0, 10);
    let conf = confPopulacao(n);
    const limiar = status === "aprovado" ? 1.2 : (status === "reprovado" ? 1.7 : 1.45);
    conf = ajustarFronteira(conf, dp, limiar, 0.3);
    cats.dispersao = montarCategoria({
      nome: "Dispersão / Consenso",
      criterio: "Aprovado: σ < 1.2★. Reprovado: σ ≥ 1.7★.",
      valor_observado: `σ=${round(dp, 2)}, CV=${round(cv, 3)}, entropia_norm=${round(ent, 3)}`,
      score, status, confiabilidade_pct: conf,
      observacao: `Desvio de ${round(dp, 2)}★ — ${dp < 1.2 ? "forte consenso" : dp < 1.7 ? "opiniões moderadamente espalhadas" : "opiniões muito divididas"}`,
    });
  })();

  (() => {
    const w95 = analise.inferencia.wilson_95;
    const amp = w95.amplitude;
    let status = "neutro";
    if (amp < 0.8) status = "aprovado";
    else if (amp >= 1.5) status = "reprovado";
    const score = clamp(10 - amp * 2.5, 0, 10);
    let conf = confPopulacao(n);
    const limiar = status === "aprovado" ? 0.8 : (status === "reprovado" ? 1.5 : 1.15);
    conf = ajustarFronteira(conf, amp, limiar, 0.4);
    cats.inferencia = montarCategoria({
      nome: "Precisão da Estimativa",
      criterio: "Aprovado: amplitude IC95% Wilson < 0.8★. Reprovado: ≥ 1.5★.",
      valor_observado: `IC95% Wilson=[${w95.inferior}, ${w95.superior}], amplitude=${amp}`,
      score, status, confiabilidade_pct: conf,
      observacao: `Margem de incerteza de ±${round(amp / 2, 2)}★ — ${amp < 0.8 ? "estimativa precisa" : amp < 1.5 ? "incerteza moderada" : "alta incerteza"}`,
    });
  })();

  (() => {
    const s = analise.sentimento;
    const pos = s.pct_positivas, neg = s.pct_negativas, nps = s.nps_adaptado;
    let status = "neutro";
    if (pos >= 65 && neg <= 25) status = "aprovado";
    else if (pos < 45 || neg > 40) status = "reprovado";
    const score = clamp(pos / 10, 0, 10);
    let conf = confPopulacao(n);
    conf = ajustarFronteira(conf, pos, status === "aprovado" ? 65 : (status === "reprovado" ? 45 : 55), 10);
    cats.sentimento = montarCategoria({
      nome: "Sentimento",
      criterio: "Aprovado: ≥65% positivas E ≤25% negativas. Reprovado: <45% positivas OU >40% negativas.",
      valor_observado: `pos=${pos}%, neu=${s.pct_neutras}%, neg=${neg}%, NPS=${nps}`,
      score, status, confiabilidade_pct: conf,
      observacao: `${pos}% positivas vs. ${neg}% negativas; NPS adaptado de ${nps} (${nps > 50 ? "muito bom" : nps > 0 ? "positivo" : "negativo"})`,
    });
  })();

  (() => {
    const f = analise.diagnostico_forma.formato;
    const idxPol = analise.diagnostico_forma.indice_polarizacao;
    const tabela = [
      [/concentrado em 5/, 9.5, "aprovado", "Consenso forte positivo"],
      [/concentrado em 4/, 8.0, "aprovado", "Maioria muito satisfeita"],
      [/decrescente típico/, 9.0, "aprovado", "Padrão saudável típico"],
      [/predominantemente positivo/, 7.0, "aprovado", "Inclinação positiva clara"],
      [/centrado em 3/, 5.0, "neutro", "Experiência mediana dominante"],
      [/uniforme/, 4.0, "neutro", "Sem padrão claro"],
      [/J shape/, 5.0, "neutro", "Viés de seleção — só extremos votam"],
      [/polarizado/, 3.5, "reprovado", "Opiniões divididas"],
      [/predominantemente negativo/, 2.5, "reprovado", "Inclinação negativa clara"],
      [/concentrado em 1/, 1.0, "reprovado", "Consenso forte negativo"],
      [/concentrado em 2/, 2.0, "reprovado", "Consenso forte negativo"],
    ];
    let score = 5, status = "neutro", obs = "Formato sem mapeamento explícito";
    for (const [rx, s, st, o] of tabela) if (rx.test(f)) { score = s; status = st; obs = o; break; }
    let conf = confPopulacao(n);
    if (idxPol < 0.15) conf *= 0.85;
    if (n < 30) conf *= 0.9;
    cats.forma = montarCategoria({
      nome: "Forma da Distribuição",
      criterio: "Aprovado: J invertido / concentrado-positivo / predominantemente positivo. Reprovado: polarizado / negativo.",
      valor_observado: `formato="${f}", índice_polarização=${idxPol}`,
      score, status, confiabilidade_pct: conf, observacao: obs,
    });
  })();

  (() => {
    const t = analise.temporal;
    if (!t || t._aviso?.includes("indisponível") || t.amostra_size === 0) {
      cats.temporal = montarCategoria({
        nome: "Estabilidade Temporal",
        criterio: "Aprovado: sem queda + última < 180d. Reprovado: queda clara OU > 365d sem reviews.",
        valor_observado: "amostra temporal vazia",
        score: 5, status: "neutro", confiabilidade_pct: 0,
        observacao: "Sem dados temporais para avaliar",
      });
      return;
    }
    const slope = t.regressao_linear?.slope_estrelas_por_ano ?? 0;
    const dias = t.dias_desde_ultima_review ?? 9999;
    const delta = t.comparacao_metades?.delta ?? 0;
    const piorando = slope < -0.3 || delta < -0.7;
    const muitoAntiga = dias > 365;
    const recente = dias < 180;
    let status = "neutro";
    if (!piorando && !muitoAntiga && recente) status = "aprovado";
    else if (piorando || muitoAntiga) status = "reprovado";
    const scoreTend = clamp(5 + slope * 5, 0, 10);
    const scoreRec = clamp(10 - (dias / 365) * 5, 0, 10);
    const score = (scoreTend + scoreRec) / 2;
    let conf = confAmostra(reviewsN);
    if (Math.abs(slope) < 0.1 && Math.abs(delta) < 0.2) conf *= 0.8;
    cats.temporal = montarCategoria({
      nome: "Estabilidade Temporal",
      criterio: "Aprovado: sem queda + última < 180d. Reprovado: queda clara OU > 365d sem reviews.",
      valor_observado: `slope=${slope}★/ano, Δ metades=${delta}, últimos=${dias}d, amostra=${reviewsN}`,
      score, status, confiabilidade_pct: conf,
      observacao: `Tendência: ${t.regressao_linear?.interpretacao ?? "n/d"}. Última review há ${round(dias, 0)} dias.`,
    });
  })();

  (() => {
    const c = analise.credibilidade;
    if (!c || c._aviso || c.amostra_size === 0) {
      cats.credibilidade = montarCategoria({
        nome: "Credibilidade dos Avaliadores",
        criterio: "Aprovado: ≤50% novatos E |Δ exp vs nov| < 1.0. Reprovado: >60% novatos OU |Δ| > 1.5.",
        valor_observado: "amostra de credibilidade vazia",
        score: 5, status: "neutro", confiabilidade_pct: 0,
        observacao: "Sem dados sobre avaliadores",
      });
      return;
    }
    const pctNov = c.pct_novatos ?? 0;
    const pctExp = c.pct_experientes ?? 0;
    const diff = c.diff_experientes_vs_novatos;
    const absDiff = diff !== null && diff !== undefined ? Math.abs(diff) : 0;
    let status = "neutro";
    if (pctNov <= 50 && absDiff < 1.0) status = "aprovado";
    else if (pctNov > 60 || absDiff > 1.5) status = "reprovado";
    const scoreExp = clamp(pctExp / 10 + 3, 0, 10);
    const scoreDiff = clamp(10 - absDiff * 4, 0, 10);
    const score = (scoreExp + scoreDiff) / 2;
    let conf = confAmostra(c.amostra_size);
    if (absDiff > 2) conf *= 1.15;
    if (c.amostra_size < 5) conf *= 0.7;
    cats.credibilidade = montarCategoria({
      nome: "Credibilidade dos Avaliadores",
      criterio: "Aprovado: ≤50% novatos E |Δ exp vs nov| < 1.0. Reprovado: >60% novatos OU |Δ| > 1.5.",
      valor_observado: `novatos=${pctNov}%, experientes=${pctExp}%, Δ=${diff}★, amostra=${c.amostra_size}`,
      score, status, confiabilidade_pct: conf,
      observacao: `${pctNov}% novatos; Δ exp vs nov=${diff ?? "n/d"}★${absDiff > 1.5 ? " → possível astroturfing" : ""}`,
    });
  })();

  (() => {
    const t = analise.textual;
    if (!t || t._aviso || t.amostra_size === 0) {
      cats.engajamento = montarCategoria({
        nome: "Engajamento do Proprietário",
        criterio: "Aprovado: engajado=true OU responde ≥40% das negativas. Reprovado: <15% geral.",
        valor_observado: "amostra textual vazia",
        score: 5, status: "neutro", confiabilidade_pct: 0,
        observacao: "Sem dados sobre respostas do estabelecimento",
      });
      return;
    }
    const respGeral = t.taxa_resposta_geral ?? 0;
    const respNeg = t.taxa_resposta_negativas;
    const engajado = t.proprietario_engajado;
    let status = "neutro";
    if (engajado || (typeof respNeg === "number" && respNeg >= 40)) status = "aprovado";
    else if (respGeral < 15) status = "reprovado";
    const score = typeof respNeg === "number"
      ? clamp((respNeg * 0.7 + respGeral * 0.3) / 10, 0, 10)
      : clamp(respGeral / 10, 0, 10);
    let conf = confAmostra(t.amostra_size);
    if (respNeg === null) conf *= 0.7;
    if (t.amostra_size < 5) conf *= 0.7;
    cats.engajamento = montarCategoria({
      nome: "Engajamento do Proprietário",
      criterio: "Aprovado: engajado=true OU responde ≥40% das negativas. Reprovado: <15% geral.",
      valor_observado: `resp_geral=${respGeral}%, resp_neg=${respNeg ?? "n/d"}%, engajado=${engajado}`,
      score, status, confiabilidade_pct: conf,
      observacao: `Dono responde ${respGeral}% em geral${typeof respNeg === "number" ? ` e ${respNeg}% das negativas` : " (sem negativas na amostra)"}`,
    });
  })();

  (() => {
    const flags = analise.red_flags ?? [];
    const altas = flags.filter(f => f.severidade === "alta").length;
    const medias = flags.filter(f => f.severidade === "média").length;
    const baixas = flags.filter(f => f.severidade === "baixa").length;
    let status = "neutro";
    if (altas === 0 && medias <= 1) status = "aprovado";
    else if (altas >= 2 || medias >= 4) status = "reprovado";
    const score = clamp(10 - (altas * 3 + medias * 1.2 + baixas * 0.4), 0, 10);
    let conf = confPopulacao(n);
    if (altas + medias >= 3) conf = Math.min(98, conf * 1.05);
    cats.red_flags = montarCategoria({
      nome: "Ausência de Red Flags",
      criterio: "Aprovado: 0 altas E ≤1 média. Reprovado: ≥2 altas OU ≥4 médias.",
      valor_observado: `altas=${altas}, médias=${medias}, baixas=${baixas}`,
      score, status, confiabilidade_pct: conf,
      observacao: flags.length === 0
        ? "Nenhum alerta detectado"
        : `${flags.length} alerta(s): ` + flags.map(f => `[${f.severidade}] ${f.flag}`).join("; "),
    });
  })();

  (() => {
    const v = analise.veredicto;
    const score = v.score_final ?? 0;
    const cls = v.classificacao ?? "❌ Indeterminado";
    let status = "neutro";
    if (score >= 7.0) status = "aprovado";
    else if (score < 4.0) status = "reprovado";
    let conf = (analise.confianca?.peso ?? 0) * 100;
    conf = ajustarFronteira(conf, score, status === "aprovado" ? 7.0 : (status === "reprovado" ? 4.0 : 5.5), 1.0);
    cats.veredicto = montarCategoria({
      nome: "Veredicto Global",
      criterio: "Aprovado: score ≥ 7.0. Reprovado: < 4.0.",
      valor_observado: `classificação="${cls}", score=${score}, confiança="${analise.confianca?.nivel ?? "n/d"}"`,
      score, status, confiabilidade_pct: conf, observacao: v.texto ?? "",
    });
  })();

  return cats;
}

// === EXTRAS ===
function gerarTags(analise, cats) {
  const tags = [];
  const f = analise.diagnostico_forma?.formato ?? "";
  if (f.includes("polarizado")) tags.push("público-dividido");
  if (f.includes("J invertido") || f.includes("decrescente")) tags.push("padrão-saudável");
  if (f.includes("concentrado em 5")) tags.push("consenso-positivo");
  if (f.includes("concentrado em 1") || f.includes("concentrado em 2")) tags.push("consenso-negativo");
  if (f.includes("J shape")) tags.push("viés-de-seleção");
  const sen = analise.sentimento;
  if (sen?.pct_positivas >= 80) tags.push("muito-positivo");
  if (sen?.pct_negativas >= 30) tags.push("muitas-reclamações");
  if (sen?.nps_adaptado >= 50) tags.push("NPS-alto");
  const t = analise.temporal;
  if (t?.amostra_size === 0) tags.push("sem-amostra-temporal");
  if (t?.regressao_linear?.interpretacao === "queda clara") tags.push("em-queda");
  if (t?.regressao_linear?.interpretacao === "melhora clara") tags.push("em-ascensão");
  if (typeof t?.dias_desde_ultima_review === "number" && t.dias_desde_ultima_review > 365) tags.push("inativo");
  const c = analise.credibilidade;
  if (c?.pct_novatos > 60) tags.push("muitos-novatos");
  const diff = c?.diff_experientes_vs_novatos;
  if (typeof diff === "number" && Math.abs(diff) > 1.5) tags.push("suspeita-astroturfing");
  const txt = analise.textual;
  if (txt?.proprietario_engajado) tags.push("dono-engajado");
  if (analise.confianca?.nivel === "muito alta") tags.push("dados-robustos");
  if (analise.confianca?.nivel === "insuficiente") tags.push("dados-insuficientes");
  if (cats.veredicto?.status === "aprovado") tags.push("recomendado");
  if (cats.veredicto?.status === "reprovado") tags.push("não-recomendado");
  return Array.from(new Set(tags));
}

function gerarHighlights(analise, cats, resumo) {
  const hs = [];
  hs.push(`${resumo.status_global} — ${resumo.aprovadas}/${resumo.total_categorias} categorias aprovadas (score categorias ${resumo.score_categorias_ponderado}/10)`);
  const ord = Object.values(cats).filter(c => c.confiabilidade_pct > 30).sort((a, b) => b.score - a.score);
  if (ord[0]) hs.push(`✚ Mais forte: ${ord[0].nome} (score ${ord[0].score}, ${ord[0].status})`);
  if (ord.length > 1) {
    const fraco = ord[ord.length - 1];
    hs.push(`✗ Mais fraco: ${fraco.nome} (score ${fraco.score}, ${fraco.status})`);
  }
  const flags = analise.red_flags ?? [];
  const flagAlta = flags.find(f => f.severidade === "alta");
  if (flagAlta) hs.push(`⚠ Alerta alto: ${flagAlta.flag}`);
  return hs;
}

function proximaAcao(resumo, cats) {
  if (resumo.status_global.includes("Reprovado")) return "Evitar — múltiplos pontos críticos";
  if (resumo.status_global.includes("Insatisfatório")) return "Buscar alternativas antes de decidir";
  if (cats.veredicto?.status === "aprovado" && resumo.reprovadas === 0) return "Pode visitar com confiança";
  if (resumo.aprovadas >= 5) return "Aceitável — verificar pontos de ressalva antes";
  return "Avaliar caso a caso";
}

// === REGRAS HARD DE REPROVAÇÃO ===
function regrasHardReprovacao({ n, minReviews, score, classificacao, conf, flags, wilson95, dist, temporalData }) {
  const motivos = [];
  const altasFlags = flags.filter(f => f.severidade === "alta").length;
  const confNivelOk = ["alta", "muito alta"].includes(conf?.nivel);

  if (n < minReviews) motivos.push(`Amostra abaixo do mínimo exigido (n=${n} < ${minReviews})`);
  if (typeof score === "number" && score >= 4.0 && score < 5.5 && !confNivelOk)
    motivos.push(`Resultado regular (score=${score}) com confiança apenas ${conf?.nivel}`);
  if (classificacao === "🔴 Ruim" || classificacao === "⛔ Péssimo")
    motivos.push(`Veredicto estatístico: ${classificacao}`);
  if (altasFlags >= 2) motivos.push(`${altasFlags} alertas críticos simultâneos`);
  if (wilson95 && typeof wilson95.superior === "number" && wilson95.superior < 3.0)
    motivos.push(`Mesmo o melhor cenário é ruim (IC95% superior=${wilson95.superior}★)`);
  if (Array.isArray(dist) && n > 0) {
    const pctNeg = ((dist[0] + dist[1]) / n) * 100;
    if (pctNeg > 60) motivos.push(`${pctNeg.toFixed(1)}% das notas são negativas (1-2★)`);
  }
  const dias = temporalData?.dias_desde_ultima_review;
  if (typeof dias === "number" && dias > 730)
    motivos.push(`Sem reviews há ${Math.round(dias)} dias (>2 anos) — possivelmente inativo`);

  return motivos;
}

// === VERIFICAÇÃO: estabelecimento fechado permanentemente ===
function isFechadoPermanente(statusRaw) {
  const s = String(statusRaw ?? "")
    .toLowerCase()
    .normalize("NFD").replace(/[\u0300-\u036f]/g, "")
    .trim();
  return (
    s.includes("fechado_permanente") ||
    s.includes("fechado permanente") ||
    s.includes("permanentemente fechado") ||
    s === "closed_permanently" ||
    s === "permanently_closed"
  );
}

// === NORMALIZAÇÃO DE TIPOS ===
function coerceItem(e) {
  const parseJSON = (v) => {
    if (typeof v !== "string") return v;
    const s = v.trim();
    if (s.startsWith("[") || s.startsWith("{")) {
      try { return JSON.parse(s); } catch { return v; }
    }
    return v;
  };
  const toNum = (v) =>
    (v === null || v === undefined || v === "") ? null
      : (typeof v === "number" ? v : (Number.isNaN(Number(v)) ? null : Number(v)));
  return {
    ...e,
    nota: toNum(e?.nota),
    qtd_avaliacoes: toNum(e?.qtd_avaliacoes),
    minimum_reviews: toNum(e?.minimum_reviews),
    distribuicao_notas: parseJSON(e?.distribuicao_notas),
    reviews: parseJSON(e?.reviews),
  };
}

// ===== PIPELINE PRINCIPAL =====
function analisar(e) {
  const nome = e?.nome ?? "(sem nome)";

  // Mínimo de avaliações exigido — vem do próprio estabelecimento (input),
  // com fallback caso o campo não esteja presente.
  const MIN_REVIEWS_DEFAULT = 10;
  const minReviews = (typeof e?.minimum_reviews === "number" && e.minimum_reviews > 0)
    ? e.minimum_reviews
    : MIN_REVIEWS_DEFAULT;

  const distMeta = (Array.isArray(e?.distribuicao_notas) && e.distribuicao_notas.length === 5)
    ? e.distribuicao_notas.map(x => Number(x) || 0)
    : [0, 0, 0, 0, 0];
  const nMeta = distMeta.reduce((a, b) => a + b, 0);
  const notaGoogleMeta = typeof e?.nota === "number" ? e.nota : null;
  const qtdAvMeta = typeof e?.qtd_avaliacoes === "number" ? e.qtd_avaliacoes : nMeta;
  const metadados = {
    subtipos: e?.subtipos ?? null,
    bairro: e?.bairro ?? null,
    cidade: e?.cidade ?? null,
    estado: e?.estado ?? null,
    endereco: e?.endereco ?? null,
    faixa_preco: e?.faixa_preco ?? null,
    status: e?.status ?? null,
    nota_google: notaGoogleMeta,
    qtd_avaliacoes: qtdAvMeta,
    distribuicao_notas: distMeta,
    minimo_avaliacoes: minReviews,
  };

  // ===== CASO 1: FECHADO PERMANENTEMENTE =====
  if (isFechadoPermanente(e?.status)) {
    const motivo = `Estabelecimento fechado permanentemente (status="${e?.status}")`;
    const vazio = {
      nome: "—", status: "reprovado", score: 0, confiabilidade_pct: 100,
      criterio: "Estabelecimento deve estar em operação.",
      valor_observado: `status="${e?.status}"`,
      observacao: motivo,
    };
    return {
      nome, metadados,
      status_global: `⛔ Reprovado — ${motivo}`,
      status_codigo: "reprovado_fechado",
      motivo_status: motivo,
      processar_qualitativo: false,
      regras_hard_violadas: [motivo],
      leitura_rapida: "Fechado permanentemente",
      score_composto_estatistico: null,
      score_categorias_ponderado: null,
      classificacao: "⛔ Fechado",
      confianca_nivel: "n/a",
      proxima_acao: "Remover da base / não recomendar — não está mais em operação",
      tags: ["fechado-permanente", "não-recomendado"],
      highlights: [`⛔ ${motivo}`],
      resumo_categorias: {
        status_global: `⛔ Reprovado — ${motivo}`,
        status_base: "⛔ Reprovado",
        status_codigo: "reprovado_fechado",
        motivo_status: motivo,
        processar_qualitativo: false,
        regras_hard_violadas: [motivo],
        aprovadas: 0, reprovadas: 10, neutras: 0, indeterminadas: 0,
        total_categorias: 10, score_categorias_ponderado: null,
        confiabilidade_media_pct: 100,
        leitura_rapida: "Fechado permanentemente",
      },
      cat_tendencia: vazio, cat_dispersao: vazio, cat_inferencia: vazio,
      cat_sentimento: vazio, cat_forma: vazio, cat_temporal: vazio,
      cat_credibilidade: vazio, cat_engajamento: vazio, cat_red_flags: vazio,
      cat_veredicto: vazio,
      analise: {
        status: "fechado_permanente",
        veredicto: {
          classificacao: "⛔ Fechado", score_final: null,
          texto: motivo,
          recomendacao: "Não recomendar — estabelecimento encerrado.",
        },
        leitura_rapida: "Fechado permanentemente",
        validacao_dados: null,
        tendencia_central: null, dispersao_forma: null, inferencia: null,
        sentimento: null, diagnostico_forma: null, temporal: null,
        credibilidade: null, textual: null,
        confianca: { nivel: "n/a", peso: 0 },
        red_flags: [{ severidade: "alta", flag: "Fechado permanentemente", detalhe: motivo }],
      },
    };
  }

  const dist = distMeta;
  const n = nMeta;
  const notaGoogle = notaGoogleMeta;
  const reviews = Array.isArray(e?.reviews) ? e.reviews : [];

  // ===== CASO 2: ZERO AVALIAÇÕES =====
  if (n === 0) {
    const vazio = {
      nome: "—", status: "indeterminado", score: null, confiabilidade_pct: 0,
      criterio: "", valor_observado: "sem dados", observacao: "Estabelecimento sem avaliações",
    };
    return {
      nome, metadados,
      status_global: "❌ Indeterminado — Sem avaliações registradas",
      status_codigo: "indeterminado",
      motivo_status: "Sem avaliações registradas (n=0)",
      processar_qualitativo: false,
      regras_hard_violadas: [],
      resumo_categorias: {
        status_global: "❌ Indeterminado — Sem avaliações registradas",
        status_base: "❌ Indeterminado",
        status_codigo: "indeterminado",
        motivo_status: "Sem avaliações registradas (n=0)",
        processar_qualitativo: false,
        aprovadas: 0, reprovadas: 0, neutras: 0, indeterminadas: 10,
        total_categorias: 10, score_categorias_ponderado: null, confiabilidade_media_pct: 0,
        leitura_rapida: "Sem avaliações",
      },
      tags: ["sem-avaliacoes", "indeterminado"],
      highlights: ["Sem avaliações registradas — análise não aplicável"],
      proxima_acao: "Buscar dados em outra fonte",
      cat_tendencia: vazio, cat_dispersao: vazio, cat_inferencia: vazio,
      cat_sentimento: vazio, cat_forma: vazio, cat_temporal: vazio,
      cat_credibilidade: vazio, cat_engajamento: vazio, cat_red_flags: vazio,
      cat_veredicto: vazio,
      analise: {
        status: "sem_avaliacoes",
        veredicto: {
          classificacao: "❌ Indeterminado", score_final: null,
          texto: "Estabelecimento sem avaliações registradas.",
          recomendacao: "Sem dados para análise.",
        },
        leitura_rapida: "Sem avaliações",
        validacao_dados: null,
        tendencia_central: null, dispersao_forma: null, inferencia: null,
        sentimento: null, diagnostico_forma: null, temporal: null,
        credibilidade: null, textual: null,
        confianca: { nivel: "insuficiente", peso: 0 },
        red_flags: [{ severidade: "alta", flag: "Sem avaliações", detalhe: "Distribuição totalmente zerada" }],
      },
    };
  }

  // ---- Blocos da análise ----
  const tc   = tendenciaCentral(dist, n);
  const df   = dispersaoForma(dist, n, tc.media);
  const inf  = inferencia(tc.media, df.variancia, n);
  const sen  = sentimento(dist, n);
  const diag = diagnosticoForma(dist, n, df.variancia);
  const tmp  = temporal(reviews);
  const cred = credibilidade(reviews);
  const txt  = analiseTextual(reviews);
  const conf = classificarConfianca(n);

  const divergencia = notaGoogle !== null ? notaGoogle - tc.media : null;
  let interpDiv = "indeterminado";
  if (divergencia !== null) {
    const ab = Math.abs(divergencia);
    interpDiv = ab < 0.15 ? "consistente" : (ab < 0.30 ? "leve divergência" : "divergente");
  }

  const flags = redFlags({
    divergencia: divergencia ?? 0, notaGoogle, mediaCalc: tc.media,
    temporalData: tmp, n, minReviews, wilson95: inf.wilson_95,
    credData: cred, diagData: diag, textualData: txt,
  });

  const score = conf.nivel === "insuficiente" ? null : scoreComposto({
    wilson95: inf.wilson_95, n,
    slopeAno: tmp?.regressao_linear?.slope_estrelas_por_ano ?? null,
    pctExperientes: cred?.pct_experientes ?? 0,
    indicePol: diag?.indice_polarizacao ?? 0,
  });

  const ver = veredicto({
    confianca: conf, score, mediaCalc: tc.media, n,
    wilson95: inf.wilson_95, diagData: diag, temporalData: tmp, flags,
  });

  const leituraRapida = `${round(tc.media, 2)} ★ (IC 95%: ${inf.wilson_95.inferior}–${inf.wilson_95.superior}, n=${n}, confiança ${conf.nivel})`;

  const analise = {
    veredicto: ver,
    leitura_rapida: leituraRapida,
    validacao_dados: {
      nota_google: notaGoogle,
      media_calculada: round(tc.media, 4),
      divergencia: divergencia !== null ? round(divergencia, 4) : null,
      interpretacao: interpDiv,
    },
    tendencia_central: tc,
    dispersao_forma: df,
    inferencia: inf,
    sentimento: sen,
    diagnostico_forma: diag,
    temporal: tmp,
    credibilidade: cred,
    textual: txt,
    confianca: conf,
    red_flags: flags,
  };

  const cats = avaliarCategorias(analise, n);

  const lista = Object.values(cats);
  const aprovadas  = lista.filter(c => c.status === "aprovado").length;
  const reprovadas = lista.filter(c => c.status === "reprovado").length;
  const neutras    = lista.filter(c => c.status === "neutro").length;

  const somaConf  = lista.reduce((s, c) => s + (c.confiabilidade_pct ?? 0), 0);
  const scoreCategoriasPond = somaConf > 0
    ? lista.reduce((s, c) => s + (c.score ?? 0) * (c.confiabilidade_pct ?? 0), 0) / somaConf
    : null;
  const confMedia = lista.reduce((s, c) => s + (c.confiabilidade_pct ?? 0), 0) / lista.length;

  let statusBase;
  if (conf.nivel === "insuficiente")            statusBase = "❌ Indeterminado";
  else if (reprovadas >= 4)                     statusBase = "⛔ Reprovado";
  else if (reprovadas >= 2 && aprovadas <= 4)   statusBase = "🔴 Insatisfatório";
  else if (aprovadas >= 7 && reprovadas === 0)  statusBase = "✅ Aprovado";
  else if (aprovadas >= 5)                      statusBase = "🟢 Aprovado com ressalvas";
  else                                          statusBase = "🟡 Parcialmente aprovado";

  const regrasHardViolated = regrasHardReprovacao({
    n, minReviews, score, classificacao: ver.classificacao, conf,
    flags, wilson95: inf.wilson_95, dist, temporalData: tmp,
  });
  if (regrasHardViolated.length > 0) statusBase = "⛔ Reprovado";

  const reprovadasList = lista.filter(c => c.status === "reprovado");
  const altasFlags     = flags.filter(f => f.severidade === "alta");

  let statusCodigo, motivoStatus, processarQualitativo;

  if (regrasHardViolated.length > 0) {
    statusCodigo = "reprovado_hard";
    processarQualitativo = false;
    motivoStatus = `Regras críticas violadas: ${regrasHardViolated.join(" | ")}`;
  } else if (statusBase.includes("❌ Indeterminado")) {
    statusCodigo = "indeterminado";
    processarQualitativo = false;
    motivoStatus = `Confiança ${conf.nivel} (n=${n}) — dados insuficientes para análise estatística`;
  } else if (statusBase.includes("⛔ Reprovado")) {
    statusCodigo = "reprovado";
    processarQualitativo = false;
    const partes = [];
    if (altasFlags.length > 0)
      partes.push(`${altasFlags.length} alerta(s) crítico(s): ${altasFlags.map(f => f.flag).join("; ")}`);
    partes.push(`${reprovadasList.length} categorias reprovadas: ${reprovadasList.map(c => c.nome).join(", ")}`);
    motivoStatus = partes.join(" | ");
  } else if (statusBase.includes("Insatisfatório")) {
    statusCodigo = "insatisfatorio";
    processarQualitativo = false;
    const partes = [];
    if (altasFlags.length > 0)
      partes.push(`${altasFlags.length} alerta(s) crítico(s): ${altasFlags.map(f => f.flag).join("; ")}`);
    partes.push(`${reprovadasList.length} reprovadas vs. ${aprovadas} aprovadas`);
    if (reprovadasList.length > 0)
      partes.push(`reprovadas em: ${reprovadasList.map(c => c.nome).join(", ")}`);
    motivoStatus = partes.join(" | ");
  } else if (statusBase.includes("✅ Aprovado")) {
    statusCodigo = "aprovado";
    processarQualitativo = true;
    motivoStatus = `${aprovadas}/${lista.length} categorias aprovadas sem reprovações`;
  } else if (statusBase.includes("ressalvas")) {
    statusCodigo = "aprovado_ressalvas";
    processarQualitativo = true;
    const partes = [`${aprovadas}/${lista.length} aprovadas, ${reprovadasList.length} ressalva(s)`];
    if (reprovadasList.length > 0)
      partes.push(`atenção em: ${reprovadasList.map(c => c.nome).join(", ")}`);
    motivoStatus = partes.join(" | ");
  } else {
    statusCodigo = "parcial";
    processarQualitativo = true;
    motivoStatus = `${aprovadas} aprovadas, ${reprovadasList.length} reprovadas, ${neutras} neutras`;
    if (reprovadasList.length > 0)
      motivoStatus += ` | reprovadas em: ${reprovadasList.map(c => c.nome).join(", ")}`;
  }

  const statusGlobal = `${statusBase} — ${motivoStatus}`;

  const resumo = {
    status_global: statusGlobal,
    status_base: statusBase,
    status_codigo: statusCodigo,
    motivo_status: motivoStatus,
    processar_qualitativo: processarQualitativo,
    regras_hard_violadas: regrasHardViolated,
    aprovadas, reprovadas, neutras,
    total_categorias: lista.length,
    score_categorias_ponderado: round(scoreCategoriasPond, 2),
    confiabilidade_media_pct: round(confMedia, 1),
    leitura_rapida: `${aprovadas}/${lista.length} aprovadas — score categorias ${round(scoreCategoriasPond, 2)}/10 (confiabilidade ${round(confMedia, 1)}%)`,
  };

  const tags = gerarTags(analise, cats);
  const highlights = gerarHighlights(analise, cats, resumo);
  const acao = proximaAcao(resumo, cats);

  return {
    nome, metadados,
    status_global: statusGlobal,
    status_codigo: statusCodigo,
    motivo_status: motivoStatus,
    processar_qualitativo: processarQualitativo,
    regras_hard_violadas: regrasHardViolated,
    leitura_rapida: leituraRapida,
    score_composto_estatistico: ver.score_final,
    score_categorias_ponderado: resumo.score_categorias_ponderado,
    classificacao: ver.classificacao,
    confianca_nivel: conf.nivel,
    proxima_acao: acao,
    tags, highlights,
    resumo_categorias: resumo,
    cat_tendencia:     cats.tendencia,
    cat_dispersao:     cats.dispersao,
    cat_inferencia:    cats.inferencia,
    cat_sentimento:    cats.sentimento,
    cat_forma:         cats.forma,
    cat_temporal:      cats.temporal,
    cat_credibilidade: cats.credibilidade,
    cat_engajamento:   cats.engajamento,
    cat_red_flags:     cats.red_flags,
    cat_veredicto:     cats.veredicto,
    analise,
  };
}

// ===== ENTRADA — Run Once for All Items =====
return $input.all().map((item) => {
  const eRaw = item.json || {};
  const eNorm = coerceItem(eRaw);
  return { json: { ...eRaw, ...analisar(eNorm) } };
});

// Mode: Run Once for All Items
// Recebe 150 itens (3 braços empilhados pelo Merge append).
// Reagrupa por ID — nunca por posição.
const all = $input.all().map(i => i.json).filter(x => x && x.id);

// Agrupa todos os fragmentos de cada estabelecimento sob o mesmo id
const porId = {};
for (const it of all) {
  if (!porId[it.id]) porId[it.id] = [];
  porId[it.id].push(it);
}

// Para cada estabelecimento, funde seus fragmentos num objeto só
return Object.values(porId).map(fragmentos => {
  // Identifica cada fragmento pelo que ele carrega de exclusivo
  const comentarios = fragmentos.find(f => f.comentarios_formatados !== undefined) || {};
  const analise     = fragmentos.find(f => f.analise !== undefined || f.score_composto_estatistico !== undefined) || {};
  const cru         = fragmentos.find(f => f.reviews !== undefined) || {};

  // Funde: base crua, depois análise, e por cima os comentários (fonte confiável do texto)
  const merged = Object.assign({}, cru, analise, comentarios);

  return { json: merged };
});

