// ============================================================================
// Função principal de classificação de UM subtipo (string única)
// ============================================================================
function classificarSubtipo(subtipo) {
  if (!subtipo || typeof subtipo !== 'string') return 'Outros';
  const s = subtipo.toLowerCase().trim();
  if (!s) return 'Outros';

  // helpers
  const has = (kw) => s.indexOf(kw) !== -1;
  const hasw = (kw) => {
    const re = new RegExp('\\b' + kw.replace(/[.*+?^${}()|[\]\\]/g, '\\$&') + '\\b', 'i');
    return re.test(s);
  };
  const hasAny = (kws) => kws.some(k => has(k));
  const hasAnyW = (kws) => kws.some(k => hasw(k));

  // ===========================================================
  // 0) EXCLUSÕES — Outros (serviços não-turísticos / hospedagem)
  //    Roda ANTES dos blocos positivos.
  // ===========================================================

  // --- Serviços originais ---
  if (hasw('veterinarian') || has('veterinár') || has('veterinario')) return 'Outros';
  if (has('pet groomer') || has('pet grooming') || has('banho e tosa')) return 'Outros';
  if (hasw('business center') || has('centro empresarial') || has('coworking')) return 'Outros';
  if (hasw('university') || hasw('universidade') || hasw('faculdade')
      || hasw('college') || has('graduate school') || has('educational institution')
      || has('public university') || has('private university')) return 'Outros';
  // Escola / curso → Outros (não há categoria turística para ensino).
  if (hasw('school')) return 'Outros';
  if (hasw('fingerprinting') || hasw('atm')) return 'Outros';
  if (has('pharmaceutical') || has('farmacêutic') || has('farmaceutic')
      || hasw('pharmacy') || hasw('farmácia') || has('drogaria')) return 'Outros';
  // >>> AJUSTE [4] clinic via word-boundary: pega 'clinic', 'pet clinic',
  //     'dental clinic', 'clínica' de forma confiável (antes 'clinic ' com espaço
  //     deixava 'pet clinic' vazar para o fallback por acaso).
  if (has('medical center') || has('hospital')
      || hasw('clinic') || has('clínica') || has('clinica')
      || has('dental') || has('dentist')) return 'Outros';
  if (has('government') || has('prefeitura') || has('câmara municipal')
      || has('cartório')) return 'Outros';
  if (has('association / organization') || has('associação')) return 'Outros';
  if (has('handicapped transportation') || has('transportation service')) return 'Outros';
  if (has('electrical repair') || has('repair shop') || has('oficina mecânica')) return 'Outros';
  if (hasw('bank') || hasw('banco') || has('embassy') || has('embaixada')
      || has('police') || has('polícia') || has('fire station') || has('bombeiro')) return 'Outros';
  if (has('laundry') || has('lavanderia') || has('gas station')
      || has('parking lot') || has('estacionamento') || has('real estate')
      || has('imobiliária') || hasw('lawyer') || has('advogado')
      || has('accountant') || has('contador') || hasw('insurance')
      || hasw('seguro') || has('delivery service')) return 'Outros';

  // --- Exclusões adicionais ---

  // Beleza / serviços pessoais (eyebrow "bar" precisa cair AQUI, antes da regra de bar)
  if (has('eyebrow') || has('brow bar') || has('sobrancelha')
      || has('eyelash') || has('cílios') || has('cilios')
      || has('nail salon') || has('manicure')
      || has('barbearia') || has('barbershop')
      || has('hair salon') || has('cabeleire')
      || has('salão de beleza') || has('salao de beleza')) return 'Outros';

  // Drogaria (reforço)
  if (has('drug store') || has('drugstore')) return 'Outros';

  // Pet services + pet shops + répteis (nenhum tem apelo turístico)
  if (has('dog walker') || has('dog walking') || has('passeador')
      || has('adestrador') || has('dog trainer')
      || has('pet shop') || has('petshop') || has('pet store') || has('pet supply')
      || has('aquarium shop') || has('reptile store')
      || has('loja de répteis') || has('loja de repteis')
      || has('animal feed')) return 'Outros';

  // Floricultura
  if (has('florist') || has('florista') || has('floricultura')
      || has('flower shop') || has('dried flower')) return 'Outros';

  // Papelaria / copiadora / material de escritório-escolar
  if (has('papelaria') || has('stationery')
      || has('copiadora') || has('copy shop')
      || has('office supply') || has('school supply') || has('material escolar')) return 'Outros';

  // Supermercado / mercearia / conveniência → Outros (loja, sem apelo turístico).
  if (has('supermercado') || has('supermarket')
      || has('hipermercado') || has('hypermarket') || has('discount supermarket')
      || has('loja de conveniência') || has('loja de conveniencia') || has('convenience store')
      || has('mercearia') || has('grocery store')) return 'Outros';

  // Cinema (precisa vir antes de Entretenimento)
  if (has('cinema') || has('movie theater')) return 'Outros';

  // Gestão / organização de eventos (precisa vir antes de Entretenimento)
  if (has('gestão de eventos') || has('gestao de eventos')
      || has('organização de eventos') || has('organizacao de eventos')
      || has('event management') || has('event planner')) return 'Outros';

  // Espaços/serviços de evento privado (aluguel p/ festa/casamento, não atração) → Outros
  if (has('event venue') || has('banquet hall') || has('salão de banquetes')
