  // PERMANECEM em Gastronomia (chocolate factory, chocolate cafe, chocolate artisan).
  if (has('candy store') || has('chocolate shop')) return 'Outros';

  // Transporte
  if (hasw('taxi') || has('táxi') || has('ponto de táxi')
      || has('car rental') || has('locadora de carro')) return 'Outros';

  // Serviços jurídicos
  if (has('legal service') || has('serviço jurídic') || has('servico juridic')
