    'observation', 'sightseeing',
    // >>> AJUSTE adições turismo:
    'boat tour', 'passeio de barco', 'boat trip',
    'cable car', 'teleférico', 'teleferico', 'bondinho',
    'lookout tower', 'torre de observação',
    'observation wheel', 'roda gigante', 'ferris wheel'
  ];
  if (hasAny(turismoLoose)) return 'Turismo e experiências';
  if (hasw('square')) return 'Turismo e experiências';
  if (hasw('park') || hasw('parque') || s === 'tour') return 'Turismo e experiências';

  return 'Outros';
}

// ============================================================================
// Tradução EN → PT de um subtipo individual (com fallback inteligente)
// ============================================================================
function traduzirSubtipo(subtipo) {
  if (!subtipo) return '';
  const original = subtipo.trim();
  const key = original.toLowerCase();
  if (TRADUCAO_SUBTIPOS[key]) return TRADUCAO_SUBTIPOS[key];

  // Fallback: tradução parcial por palavras-chave comuns
  let traduzido = original;
  const mapaFallback = [
    [/^(.+) restaurant$/i, 'Restaurante $1'],
    [/^(.+) store$/i, 'Loja de $1'],
    [/^(.+) shop$/i, 'Loja de $1'],
    [/^(.+) bar$/i, '$1 bar']
  ];
  for (const [re, repl] of mapaFallback) {
    if (re.test(original)) {
      traduzido = original.replace(re, repl);
      break;
    }
  }
  return traduzido;
}

// ============================================================================
// Classifica um estabelecimento (com múltiplos subtipos)
// ============================================================================
function classificarEstabelecimento(subtiposStr) {
  const resultado = {
    categoria_principal: 'Outros',
    categorias: [],
    subtipos_normalizados: [],
    subtipos_pt: []
  };

  if (!subtiposStr || typeof subtiposStr !== 'string') return resultado;

  const lista = subtiposStr.split(',').map(x => x.trim()).filter(Boolean);
  resultado.subtipos_normalizados = lista;

  const catsEncontradas = [];
  for (const sub of lista) {
    const cat = classificarSubtipo(sub);
    if (!catsEncontradas.includes(cat)) catsEncontradas.push(cat);
    resultado.subtipos_pt.push(traduzirSubtipo(sub));
  }

  resultado.categorias = catsEncontradas;

  if (catsEncontradas.length === 0) {
    resultado.categoria_principal = 'Outros';
    return resultado;
  }

  // Escolhe principal: prefere categorias != Outros, por ordem de prioridade
  const validas = catsEncontradas.filter(c => c !== 'Outros');
  const pool = validas.length > 0 ? validas : catsEncontradas;

  for (const prio of CATS_PRIORIDADE) {
    if (pool.includes(prio)) {
      resultado.categoria_principal = prio;
      return resultado;
    }
  }
  resultado.categoria_principal = pool[0];
  return resultado;
}

// ============================================================================
// LOOP n8n — processa todos os itens
// ============================================================================
const outputs = [];

for (const item of $input.all()) {
  const data = item.json;

  // campo correto é `subsegmento`
  const subtiposStr = data.subsegmento || '';

  const classif = classificarEstabelecimento(subtiposStr);

  outputs.push({
    json: {
      ...data,
      categoria_principal: classif.categoria_principal,
      categorias: classif.categorias,
      subtipos_normalizados: classif.subtipos_normalizados,
      subtipos_pt: classif.subtipos_pt,
      subtipos_pt_str: classif.subtipos_pt.join(', ')
    }
  });
}

return outputs;

// === n8n Code Node (Run Once for All Items) ===

// 1. Normaliza a entrada: lista única de objetos, venham como itens
//    separados ou como array dentro de um único item.
let registros = [];

for (const item of items) {
  const j = item.json;
  if (Array.isArray(j)) {
    registros.push(...j);
  } else if (Array.isArray(j.data)) {
    registros.push(...j.data);
  } else {
    registros.push(j);
  }
}

// 2. Extrai o minimum_reviews (linha de config no fim, sem id)
let minimumReviews = null;
const cfg = registros.find(
  (r) => r && r.minimum_reviews !== undefined && r.id === undefined
);
if (cfg) minimumReviews = cfg.minimum_reviews;

// 3. Injeta em cada estabelecimento (linhas que têm id)
return registros
  .filter((r) => r && r.id !== undefined)
  .map((r) => ({
    json: {
      ...r,
      minimum_reviews: minimumReviews,
    },
  }));
